// Purpose: TS mirror of the shared tool registry — builds Anthropic tool specs,
// validates the config against the dispatcher, and runs each tool against Convex.
//
// The six tools have the SAME names/schemas as the Python CLI, but are implemented
// against Convex tables (the server has no access to the user's local files).

import type { AutomationConfig, ToolSpec } from "./config";
// `internal` is generated by `npx convex dev`. Until you run it, this import (and the
// _generated folder) will not exist — that is expected. See web/README.md.
import { internal } from "../convex/_generated/api";

/** The shape Anthropic's `messages.create({ tools })` expects. */
export interface AnthropicTool {
  name: string;
  description: string;
  input_schema: Record<string, unknown>;
}

/**
 * Minimal Convex action-context surface the dispatcher needs. The real
 * `ActionCtx` from convex/_generated/server is structurally compatible with this,
 * so you can pass it straight through.
 */
export interface ToolCtx {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  runQuery: (reference: any, args?: any) => Promise<any>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  runMutation: (reference: any, args?: any) => Promise<any>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  runAction: (reference: any, args?: any) => Promise<any>;
}

/** Map the config's tool specs into the array Anthropic expects. */
export function buildAnthropicTools(config: AutomationConfig): AnthropicTool[] {
  return config.tools.map((spec: ToolSpec) => ({
    name: spec.name,
    description: spec.description,
    input_schema: spec.input_schema as unknown as Record<string, unknown>,
  }));
}

type ToolInput = Record<string, unknown>;
type Handler = (input: ToolInput, ctx: ToolCtx) => Promise<string>;

function str(input: ToolInput, key: string): string {
  const v = input[key];
  return typeof v === "string" ? v : "";
}

/**
 * The dispatcher registry, keyed by tool name (which equals `handler` in the config).
 * Every handler returns a plain string — exactly what gets put in the model's
 * `tool_result` block.
 */
const handlers: Record<string, Handler> = {
  // 1. Read the latest `documents` row whose name == path.
  read_document: async (input, ctx) => {
    const path = str(input, "path");
    if (!path) return "Error: `path` is required.";
    const doc = await ctx.runQuery(internal.store.getDocument, { name: path });
    if (!doc) return `No document named "${path}" was found in the workspace.`;
    return `--- ${doc.name} ---\n${doc.content}`;
  },

  // 2. List `documents` names, optionally filtered by substring.
  list_workspace: async (input, ctx) => {
    const pattern = str(input, "pattern");
    const names: string[] = await ctx.runQuery(internal.store.listDocuments, {
      pattern: pattern || undefined,
    });
    if (names.length === 0) {
      return pattern
        ? `No documents match "${pattern}".`
        : "The workspace has no documents yet.";
    }
    return `Documents (${names.length}):\n` + names.map((n) => `- ${n}`).join("\n");
  },

  // 3. Insert or replace a `documents` row.
  write_deliverable: async (input, ctx) => {
    const filename = str(input, "filename");
    const content = str(input, "content");
    if (!filename) return "Error: `filename` is required.";
    await ctx.runMutation(internal.store.writeDocument, { name: filename, content });
    return `Wrote deliverable "${filename}" (${content.length} characters).`;
  },

  // 4. Append a structured record to the `records` table.
  save_record: async (input, ctx) => {
    const table = str(input, "table");
    const data = (input["data"] ?? {}) as Record<string, unknown>;
    if (!table) return "Error: `table` is required.";
    await ctx.runMutation(internal.store.addRecord, { table, data });
    return `Saved 1 record to "${table}": ${JSON.stringify(data)}`;
  },

  // 5. Substring-search records in a table.
  lookup_record: async (input, ctx) => {
    const table = str(input, "table");
    const query = str(input, "query");
    if (!table) return "Error: `table` is required.";
    const rows: Array<{ data: Record<string, unknown> }> = await ctx.runQuery(
      internal.store.queryRecords,
      { table, query: query || undefined },
    );
    if (rows.length === 0) {
      return query
        ? `No records in "${table}" match "${query}".`
        : `No records in "${table}" yet.`;
    }
    const body = rows.map((r, i) => `${i + 1}. ${JSON.stringify(r.data)}`).join("\n");
    return `Found ${rows.length} record(s) in "${table}":\n${body}`;
  },

  // 6. Create a follow-up task.
  create_task: async (input, ctx) => {
    const title = str(input, "title");
    const due = str(input, "due");
    const notes = str(input, "notes");
    if (!title) return "Error: `title` is required.";
    await ctx.runMutation(internal.store.addTask, {
      title,
      due: due || undefined,
      notes: notes || undefined,
    });
    return `Created task "${title}"${due ? ` (due ${due})` : ""}.`;
  },
};

