/** Names the dispatcher knows how to run. */
export const KNOWN_HANDLERS: readonly string[] = Object.keys(handlers);

/**
 * Assert every `config.tools[*].handler` is implemented here. Throws (listing the
 * gaps) so a misconfigured contract fails loudly at startup instead of mid-run.
 */
export function validateConfigTools(config: AutomationConfig): void {
  const missing = config.tools
    .map((t) => t.handler)
    .filter((h) => !(h in handlers));
  if (missing.length > 0) {
    throw new Error(
      `automation.config.json references unknown tool handler(s): ${missing.join(
        ", ",
      )}. Known handlers: ${KNOWN_HANDLERS.join(", ")}.`,
    );
  }
}

/**
 * Execute a single tool call and return the string the model should see as its
 * `tool_result`. `name` is the Anthropic tool name (identical to the config handler).
 */
export async function dispatchTool(
  name: string,
  input: ToolInput,
  ctx: ToolCtx,
): Promise<string> {
  const handler = handlers[name];
  if (!handler) {
    return `Error: no handler registered for tool "${name}".`;
  }
  try {
    return await handler(input, ctx);
  } catch (err) {
    return `Error while running "${name}": ${
      err instanceof Error ? err.message : String(err)
    }`;
  }
}
